// delete: тот же resolve issue_id что и в update, отдельная нода для чистоты графа.
const src = $input.first().json;
const issueName = String((src.params && src.params.issue_name) || '').trim().toLowerCase();
if (!issueName) {
  return [{ json: { ...src, _resolve_error: 'Не указано название задачи' } }];
}
const url = `${src.plane_url}/api/v1/workspaces/${src.workspace_slug}/projects/${src.project_id}/issues/?per_page=100`;
try {
  const resp = await this.helpers.httpRequest({
    method: 'GET', url, headers: {
      'X-API-Key': src.plane_token,
      'Content-Type': 'application/json'
    }, timeout: 15000, json: true
  });
  const issues = Array.isArray(resp) ? resp : (resp.results || []);
  const found = issues.find(i => String(i.name || '').toLowerCase() === issueName);
  if (!found) {
    return [{ json: { ...src, _resolve_error: `Задача «${src.params.issue_name}» не найдена в проекте ${src.project_name_canonical}` } }];
  }
  return [{ json: { ...src, issue_id: found.id, issue_name_canonical: found.name } }];
} catch (e) {
  return [{ json: { ...src, _resolve_error: 'Ошибка поиска задачи: ' + (e.message || e) } }];
}

// Единый форматтер для всех веток (list_projects, list_issues, create, update, delete, search, chat).
// На входе либо родительский json (из Parse LLM) + api-результат, либо api-ответ.
// Задача: собрать чистый { response, action, data, error } для фронта.

// Универсальный поиск "src" — либо из Parse LLM (NL mode), либо Direct resolve (bypass).
function getSrc() {
  try { return $('Parse LLM').first().json; } catch(_) {}
  try { return $('Direct resolve').first().json; } catch(_) {}
  return {};
}
const src = getSrc();
const input = $input.first().json || {};

const action = src.action || 'chat';
// Расширенные actions — большинство ходят через update_issue: PATCH, для них
// формат ответа аналогичен update. get_issue — возвращаем единый issue object.
// add_comment — успех если HTTP 200.
const PATCH_ACTIONS = ['change_status','assign_issue','set_deadline','add_label','remove_label'];
const llm_text = src.llm_text || '';

// Для chat-веток (или если LLM упал) — просто текст
if (action === 'chat' || src.llm_error) {
  return [{ json: {
    response: llm_text || 'Готово.',
    action: 'chat',
    data: null
  } }];
}

// Resolve-ошибка (update/delete не нашли задачу) живёт в выходе resolve-ноды,
// НЕ в input (input — это ответ PATCH/DELETE который выполнился с issue_id=undefined).
// Достаём из соответствующей ноды по имени.
function getResolveError() {
  if (action === 'update_issue') {
    try { return $('update: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  } else if (action === 'delete_issue') {
    try { return $('delete: resolve issue_id').first().json._resolve_error || null; } catch(_) {}
  }
  return null;
}
const resolveErr = getResolveError() || input._resolve_error;
if (resolveErr) {
  return [{ json: {
    response: resolveErr,
    action,
    data: null,
    error: resolveErr
  } }];
}

// Plane API мог вернуть ошибку. Бывает любой формы: string в r.error/r.detail,
// объект-словарь field errors (DRF validation: {field: ["msg"]}), список и т.п.
// Раньше String(объект) давал "[object Object]". Теперь — JSON.stringify для не-строк.
function toErrStr(v) {
  if (v == null) return null;
  if (typeof v === 'string') return v;
  try { return JSON.stringify(v); } catch(_) { return String(v); }
}
function planeError(r) {
  if (!r || typeof r !== 'object') return null;
  if (r.error)         return toErrStr(r.error);
  if (r.detail)        return toErrStr(r.detail);
  if (r.error_message) return toErrStr(r.error_message);
  if (r.status_code && r.status_code >= 400) return `HTTP ${r.status_code}`;
  // DRF validation errors: { name: ["required"], ... } — корневой объект без error/detail,
  // зато все значения — массивы строк. Сериализуем целиком.
  const keys = Object.keys(r);
  if (keys.length > 0 && keys.every(k => Array.isArray(r[k]))) {
    return toErrStr(r);
  }
  return null;
}

// === list_projects ===
if (action === 'list_projects') {
  const projects = (input.api_result && input.api_result.projects) || src.projects || [];
  return [{ json: {
    response: llm_text + (projects.length === 0 ? '\n\nНет доступных проектов.' : ''),
    action,
    data: { projects: projects.map(p => ({ id: p.id, name: p.name, identifier: p.identifier })) }
  } }];
}

// === list_issues / search_issues ===
if (action === 'list_issues' || action === 'search_issues') {
  const err = planeError(input);
  if (err) {
    return [{ json: { response: `Не удалось получить задачи: ${err}`, action, data: null, error: err } }];
  }
  let issues = Array.isArray(input) ? input : (input.results || []);
  // search_issues: Plane v0.27 не всегда фильтрует через ?search=, дофильтровываем
  // на клиенте по подстроке в name. Если query пустой — возвращаем всё (как list).
  if (action === 'search_issues') {
    const q = String((src.params && src.params.query) || '').toLowerCase().trim();
    if (q) {
      issues = issues.filter(i => String(i.name || '').toLowerCase().includes(q));
    }
  }
  return [{ json: {
    response: llm_text + (issues.length === 0 ? '\n\nЗадач не найдено.' : `\n\nНайдено: ${issues.length}.`),
    action,
    data: {
      project: src.project_name_canonical,
      issues: issues.map(i => ({
        id: i.id,
        name: i.name,
        priority: i.priority,
        state: i.state,
        sequence_id: i.sequence_id,
        created_at: i.created_at
      }))
    }
  } }];
}

// === create_issue ===
if (action === 'create_issue') {
  const err = planeError(input);
  if (err) {
    return [{ json: { response: `Не удалось создать задачу: ${err}`, action, data: null, error: err } }];
  }
  return [{ json: {
    response: llm_text + ` Задача создана: ${input.name} (#${input.sequence_id || '?'}).`,
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority } }
  } }];
}

// === update_issue ===
if (action === 'update_issue') {
  const err = planeError(input);
  if (err) {
    return [{ json: { response: `Не удалось обновить задачу: ${err}`, action, data: null, error: err } }];
  }
  return [{ json: {
    response: llm_text + ` Задача обновлена: ${input.name || src.params.issue_name}.`,
    action,
    data: { issue: { id: input.id, name: input.name, sequence_id: input.sequence_id, priority: input.priority } }
  } }];
}

// === delete_issue ===
if (action === 'delete_issue') {
  const err = planeError(input);
  if (err) {
    return [{ json: { response: `Не удалось удалить задачу: ${err}`, action, data: null, error: err } }];
  }
  return [{ json: {
    response: llm_text + ` Задача удалена.`,
    action,
    data: null
  } }];
}

// Фоллбек
return [{ json: { response: llm_text || 'Готово.', action, data: null } }];

// Resolve для extended-actions (change_status, set_deadline, assign_issue,
// add_label, remove_label, add_comment, get_issue).
// Находит issue_id по issue_name. Если params.state есть — берёт state_id
// из загруженных states. Если params.labels (массив имён) — резолвит label_ids.
const src = $input.first().json;
const params = src.params || {};

// Найти issue_id
let issue_id = null;
let issue_obj = null;
const issues = src.issues || [];
const wantedIssue = String(params.issue_name || '').toLowerCase().trim();
if (wantedIssue) {
  issue_obj = issues.find(i => String(i.name || '').toLowerCase() === wantedIssue);
  if (issue_obj) issue_id = issue_obj.id;
}
if (!issue_id && wantedIssue) {
  return [{ json: { ...src, _resolve_error: `Не нашёл задачу «${params.issue_name}». Доступные: ${issues.slice(0,5).map(i=>i.name).join(', ')}.` } }];
}

// Резолв state_id из params.state (если есть)
let state_id = null;
if (params.state) {
  const states = src._states || [];
  const wantedState = String(params.state).toLowerCase().trim();
  // Сначала по точному совпадению name, потом по group (backlog/unstarted/started/completed/cancelled)
  const stateByName = states.find(s => String(s.name || '').toLowerCase() === wantedState);
  const stateByGroup = states.find(s => String(s.group || '').toLowerCase() === wantedState);
  // Семантические aliases для русских и популярных терминов
  const ALIASES = {
    'тудо':'unstarted','todo':'unstarted','к выполнению':'unstarted','новая':'unstarted',
    'в работе':'started','в процессе':'started','in progress':'started','делается':'started',
    'готово':'completed','done':'completed','завершено':'completed','выполнено':'completed',
    'отменено':'cancelled','cancelled':'cancelled','отмена':'cancelled',
    'бэклог':'backlog','backlog':'backlog','очередь':'backlog'
  };
  const aliased = ALIASES[wantedState];
  const stateByAlias = aliased ? states.find(s => String(s.group || '').toLowerCase() === aliased) : null;
  const state = stateByName || stateByGroup || stateByAlias;
  if (state) state_id = state.id;
}

return [{ json: { ...src, issue_id, issue_obj, state_id } }];
